<span class="line"><span style="color:#D73A49;--shiki-dark:#81A1C1">    private</span><span style="color:#24292E;--shiki-dark:#81A1C1"> $</span><span style="color:#24292E;--shiki-dark:#D8DEE9">lockName</span><span style="color:#24292E;--shiki-dark:#81A1C1">;</span></span>
