<span class="line"><span style="color:#005CC5;--shiki-dark:#88C0D0">        stream_copy_to_stream</span><span style="color:#24292E;--shiki-dark:#ECEFF4">(</span><span style="color:#24292E;--shiki-dark:#81A1C1">$</span><span style="color:#24292E;--shiki-dark:#D8DEE9">chunkFile</span><span style="color:#24292E;--shiki-dark:#ECEFF4">,</span><span style="color:#24292E;--shiki-dark:#81A1C1"> $</span><span style="color:#24292E;--shiki-dark:#D8DEE9">finalFile</span><span style="color:#24292E;--shiki-dark:#ECEFF4">)</span><span style="color:#24292E;--shiki-dark:#81A1C1">;</span></span>
